changeSet.sql:
DELETE FROM provider_attribute WHERE provider_attribute_type_id IN
    (SELECT provider_attribute_type_id FROM provider_attribute_type WHERE name = 'Available for appointments');
DELETE FROM provider_attribute_type WHERE name = 'Available for appointments';

INSERT INTO patient_appointment_provider (patient_appointment_id, provider_id, response, date_created, creator, uuid)
SELECT a.patient_appointment_id, a.provider_id, 'ACCEPTED', a.date_created, a.creator, UUID()
FROM patient_appointment a WHERE a.provider_id IS NOT NULL;

INSERT INTO patient_appointment_provider (patient_appointment_id, provider_id, response, date_created, creator, uuid)
SELECT a.patient_appointment_id, a.provider_id, 'ACCEPTED', a.date_created, a.creator, gen_random_uuid()
FROM patient_appointment a WHERE a.provider_id IS NOT NULL;

INSERT INTO person_attribute_type (name, description, format, searchable, creator, date_created, retired, uuid)
VALUES ('email', 'Email Address', 'java.lang.String', TRUE, 1, CURRENT_TIMESTAMP, FALSE, gen_random_uuid())
